#!/usr/bin/env python3

import os
import sys
import shutil
import subprocess
from pathlib import Path

ROOT = Path(__file__).resolve().parent
DIST_DIR = ROOT / "dist"
BUILD_DIR = ROOT / "build"
REQUIREMENTS = ROOT / "requirements.txt"


def run(cmd, check=True):
    print(">", " ".join(cmd), flush=True)
    return subprocess.run(cmd, cwd=ROOT, check=check)


def ensure_requirements():
    if not REQUIREMENTS.exists():
        print(f"Missing {REQUIREMENTS}", file=sys.stderr)
        sys.exit(1)


def install_dependencies():
    run([sys.executable, "-m", "pip", "install", "--upgrade", "pip"])
    run([sys.executable, "-m", "pip", "install", "-r", str(REQUIREMENTS)])


def run_tests():
    pytest_ini = ROOT / "pytest.ini"
    tests_dir = ROOT / "tests"
    if pytest_ini.exists() or tests_dir.exists():
        run([sys.executable, "-m", "pytest", "-q"])
    else:
        print("No tests found, skipping.")


def clean():
    for path in (DIST_DIR, BUILD_DIR):
        if path.exists():
            shutil.rmtree(path)
    for pattern in ("*.egg-info",):
        for path in ROOT.glob(pattern):
            if path.is_dir():
                shutil.rmtree(path)
            else:
                path.unlink()


def package():
    pyproject = ROOT / "pyproject.toml"
    setup_py = ROOT / "setup.py"
    if pyproject.exists() or setup_py.exists():
        run([sys.executable, "-m", "pip", "install", "build"])
        run([sys.executable, "-m", "build", "--outdir", str(DIST_DIR)])
        return

    DIST_DIR.mkdir(parents=True, exist_ok=True)
    archive_base = DIST_DIR / ROOT.name
    archive = shutil.make_archive(str(archive_base), "zip", root_dir=ROOT)
    print(f"Created package: {archive}")


def main():
    ensure_requirements()
    clean()
    install_dependencies()
    run_tests()
    package()
    print("Deployment build completed successfully.")


if __name__ == "__main__":
    main()